  const scheduler = new TaskScheduler();
  let count1 = 0, count2 = 0;

  scheduler.scheduleTask(() => count1++, 100);
  scheduler.scheduleTask(() => count2++, 100);

  setTimeout(() => {
    expect(count1).toBeGreaterThan(0);
    expect(count2).toBeGreaterThan(0);
    done();
  }, 350);
});

