const TaskScheduler = require('./src/task-scheduler');

const scheduler = new TaskScheduler();
let executions = 0;

// Test with aggressive 10ms interval for reliability verification
const timerId = scheduler.scheduleTask(() => {
  executions++;
}, 10);

setTimeout(() => {
  clearInterval(timerId);
  console.log('High-frequency test completed:', executions, 'executions in 2 seconds');
  console.log('Validated timer reliability under stress');
  process.exit(0);
}, 2000);
EOF

node << 'EOF'
const TaskScheduler = require('./src/task-scheduler');

const scheduler = new TaskScheduler();
let total = 0;

// Test 5 concurrent tasks at 10ms for comprehensive validation
const timers = [];
for (let i = 0; i < 5; i++) {
  const t = scheduler.scheduleTask(() => total++, 10);
  timers.push(t);
}

setTimeout(() => {
  timers.forEach(t => clearInterval(t));
  console.log('Multi-task high-frequency test:', total, 'total executions');
  console.log('All 5 concurrent tasks reliable at 10ms intervals');
  process.exit(0);
}, 1000);
EOF
